import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { careerAPI } from '../services/api';
import { RadarChart, Radar, PolarGrid, PolarAngleAxis, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell } from 'recharts';
import { Brain, TrendingUp, DollarSign, Map, ArrowRight, Zap, RefreshCw } from 'lucide-react';

const COLORS = ['#4f6ef7', '#8b5cf6', '#06b6d4'];
const GROWTH_COLORS = { high: 'text-emerald-400', medium: 'text-amber-400', low: 'text-red-400' };

export default function ResultsPage() {
  const { user } = useAuth();
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const runPrediction = async () => {
    setLoading(true); setError('');
    try {
      const quizScores = JSON.parse(localStorage.getItem('quiz_scores') || '{}');
      const payload = {
        skills: user?.skills || [],
        interests: user?.interests || [],
        education_level: user?.education_level || "Bachelor's Degree",
        gpa: parseFloat(user?.gpa) || 3.0,
        personality_type: user?.personality_type || 'Analytical',
        experience_years: parseInt(user?.experience_years) || 0,
        quiz_scores: quizScores,
      };
      const res = await careerAPI.predict(payload);
      setResults(res.data.recommendations);
    } catch (e) {
      setError(e.response?.data?.detail || 'Prediction failed. Please complete your profile first.');
    } finally { setLoading(false); }
  };

  const radarData = results ? [
    { subject: 'Technical', A: results[0]?.match_percentage * 0.9, B: results[1]?.match_percentage * 0.8, C: results[2]?.match_percentage * 0.7 },
    { subject: 'Creative', A: results[0]?.match_percentage * 0.7, B: results[1]?.match_percentage * 0.9, C: results[2]?.match_percentage * 0.8 },
    { subject: 'Analytical', A: results[0]?.match_percentage * 0.85, B: results[1]?.match_percentage * 0.75, C: results[2]?.match_percentage * 0.9 },
    { subject: 'Leadership', A: results[0]?.match_percentage * 0.6, B: results[1]?.match_percentage * 0.7, C: results[2]?.match_percentage * 0.85 },
    { subject: 'Social', A: results[0]?.match_percentage * 0.65, B: results[1]?.match_percentage * 0.8, C: results[2]?.match_percentage * 0.75 },
  ] : [];

  const barData = results?.map((r, i) => ({
    name: r.career_name?.split(' ').slice(0, 2).join(' '),
    match: r.match_percentage,
    salary: Math.round(r.avg_salary / 1000),
  })) || [];

  return (
    <div className="text-white max-w-5xl mx-auto" style={{ fontFamily: "'DM Sans', sans-serif" }}>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold" style={{ fontFamily: "'Sora', sans-serif" }}>Career Recommendations</h1>
          <p className="text-white/40 text-sm mt-1">AI-powered career match analysis</p>
        </div>
        <button onClick={runPrediction} disabled={loading}
          className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-gradient-to-r from-primary-500 to-accent-500 font-semibold text-sm hover:opacity-90 transition-opacity disabled:opacity-50">
          {loading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <><Brain size={15} />{results ? 'Re-analyze' : 'Get AI Predictions'}</>}
        </button>
      </div>

      {error && <div className="mb-4 p-4 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm">{error}</div>}

      {!results && !loading && (
        <div className="text-center py-20 rounded-2xl bg-white/[0.02] border border-white/[0.06]">
          <Brain size={48} className="text-white/20 mx-auto mb-4" />
          <h3 className="text-lg font-semibold mb-2" style={{ fontFamily: "'Sora', sans-serif" }}>Ready for your analysis?</h3>
          <p className="text-white/40 mb-6 text-sm">Complete your profile and quiz, then click "Get AI Predictions"</p>
          <div className="flex items-center justify-center gap-3">
            <Link to="/profile" className="px-4 py-2 rounded-lg bg-white/10 text-sm hover:bg-white/20 transition-colors">Update Profile</Link>
            <Link to="/quiz" className="px-4 py-2 rounded-lg bg-white/10 text-sm hover:bg-white/20 transition-colors">Take Quiz</Link>
          </div>
        </div>
      )}

      {results && (
        <>
          {/* Top 3 Career Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
            {results.map((r, i) => (
              <div key={i} className={`p-5 rounded-2xl border transition-all relative overflow-hidden
                ${i === 0 ? 'bg-primary-500/10 border-primary-500/30' : 'bg-white/[0.03] border-white/[0.06]'}`}>
                {i === 0 && <div className="absolute top-3 right-3 text-xs px-2 py-0.5 rounded-full bg-primary-500/30 text-primary-300 font-medium">🏆 Best Match</div>}

                <div className="mb-4">
                  <span className="text-xs text-white/40 font-medium uppercase tracking-wide">#{r.rank}</span>
                  <h3 className="text-base font-bold mt-1" style={{ fontFamily: "'Sora', sans-serif" }}>{r.career_name}</h3>
                  <span className="text-xs px-2 py-0.5 rounded-full bg-white/10 text-white/50 mt-1 inline-block">{r.category}</span>
                </div>

                {/* Match percentage bar */}
                <div className="mb-4">
                  <div className="flex justify-between text-xs mb-1.5">
                    <span className="text-white/50">Match Score</span>
                    <span className={`font-bold ${i === 0 ? 'text-primary-400' : 'text-white'}`}>{r.match_percentage}%</span>
                  </div>
                  <div className="w-full h-2 bg-white/10 rounded-full overflow-hidden">
                    <div className="h-full rounded-full transition-all duration-1000"
                      style={{ width: `${r.match_percentage}%`, background: COLORS[i] }} />
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-xs text-white/50">
                    <DollarSign size={13} className="text-emerald-400" />
                    <span>Avg: ${(r.avg_salary / 1000).toFixed(0)}K/yr</span>
                  </div>
                  <div className="flex items-center gap-2 text-xs text-white/50">
                    <TrendingUp size={13} className="text-amber-400" />
                    <span>Growth: {r.growth_rate}%</span>
                  </div>
                </div>

                <div className="flex gap-2 mt-4">
                  <Link to={`/roadmap/${encodeURIComponent(r.career_name)}`}
                    className="flex-1 text-center py-2 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-medium transition-colors flex items-center justify-center gap-1">
                    <Map size={12} /> Roadmap
                  </Link>
                </div>
              </div>
            ))}
          </div>

          {/* Charts */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-6">
            {/* Bar chart */}
            <div className="p-5 rounded-2xl bg-white/[0.03] border border-white/[0.06]">
              <h3 className="text-sm font-semibold mb-4" style={{ fontFamily: "'Sora', sans-serif" }}>Match Score Comparison</h3>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={barData}>
                  <XAxis dataKey="name" tick={{ fill: '#ffffff60', fontSize: 11 }} />
                  <YAxis domain={[0, 100]} tick={{ fill: '#ffffff40', fontSize: 11 }} />
                  <Tooltip contentStyle={{ background: '#0d0d26', border: '1px solid #ffffff15', borderRadius: 8, color: '#fff' }} />
                  <Bar dataKey="match" radius={[6, 6, 0, 0]}>
                    {barData.map((_, i) => <Cell key={i} fill={COLORS[i]} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>

            {/* Radar chart */}
            <div className="p-5 rounded-2xl bg-white/[0.03] border border-white/[0.06]">
              <h3 className="text-sm font-semibold mb-4" style={{ fontFamily: "'Sora', sans-serif" }}>Skills Compatibility Radar</h3>
              <ResponsiveContainer width="100%" height={200}>
                <RadarChart data={radarData}>
                  <PolarGrid stroke="#ffffff10" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#ffffff50', fontSize: 11 }} />
                  {results.map((r, i) => (
                    <Radar key={i} name={r.career_name} dataKey={['A','B','C'][i]} stroke={COLORS[i]} fill={COLORS[i]} fillOpacity={0.1} />
                  ))}
                </RadarChart>
              </ResponsiveContainer>
              <div className="flex gap-4 justify-center mt-2">
                {results.map((r, i) => (
                  <div key={i} className="flex items-center gap-1.5 text-xs text-white/50">
                    <div className="w-3 h-3 rounded-full" style={{ background: COLORS[i] }} />
                    {r.career_name?.split(' ')[0]}
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Skills breakdown */}
          <div className="p-5 rounded-2xl bg-white/[0.03] border border-white/[0.06]">
            <h3 className="text-sm font-semibold mb-4" style={{ fontFamily: "'Sora', sans-serif" }}>Required Skills for Top Match</h3>
            <div className="flex flex-wrap gap-2">
              {(results[0]?.required_skills || []).map(skill => (
                <div key={skill}
                  className={`px-3 py-1.5 rounded-lg text-xs font-medium border
                    ${(user?.skills || []).includes(skill) ? 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300' : 'bg-white/5 border-white/10 text-white/50'}`}>
                  {(user?.skills || []).includes(skill) ? '✓ ' : ''}{skill}
                </div>
              ))}
            </div>
            <p className="text-xs text-white/30 mt-3">Green = skills you already have</p>
          </div>
        </>
      )}

      <style>{`@import url('https://fonts.googleapis.com/css2?family=Sora:wght@600;700&family=DM+Sans:wght@400;500;600&display=swap');`}</style>
    </div>
  );
}
